class LinkedList {
    constructor() {
        this.head = null;
        this.tail = null;
    }

    insertAtIndex(index, value) {
        let newNode = new Node(value);

        if (index === 0) {
            // Insert at head
            newNode.next = this.head;
            if (this.head !== null) {
                this.head.prev = newNode;
            }
            this.head = newNode;
        } else {
            // Insert at any other position
            let iter = this.head;
            for (let i = 0; i < index - 1; i++) {
                iter = iter.next;
            }

            let A = iter;
            let B = iter.next;

            // Update pointers to insert newNode between A and B
            A.next = newNode;
            if (B !== null) {
                B.prev = newNode;
            }

            newNode.next = B;
            newNode.prev = A;
        }
    }

    printValues() {
        if (this.head === null) {
            return;
        } else {
            let current = this.head;
            let values = [];
            while (current !== null) {
                values.push(current.value);
                current = current.next;
            }
            console.log(values.join(' '));
        }
    }
}
